```sql
SELECT * FROM clients ORDER BY age DESC;
```

```sql
SELECT * FROM clients WHERE age > 18 AND ville = "Lyon";
```

```sql
SELECT * FROM clients WHERE ville IN ("Lyon", "Paris");
```

```sql
SELECT * FROM clients WHERE nom LIKE "A%";
```

```sql
SELECT pays, COUNT(*) FROM clients GROUP BY pays;
```

```sql
SELECT pays, COUNT(*) FROM clients GROUP BY pays HAVING COUNT(*) > 5;
```
